const allRows = $input.all();
if (allRows.length === 0) return []; 

const lastRow = allRows.at(-1).json;

// 1. Incident ID Logic
const sheetID = String(lastRow['Incident ID'] || '').trim();
const rowNum  = lastRow['row_number'] ?? lastRow['__rowNumber'] ?? Date.now();
const incidentId = sheetID || ('INC-' + String(rowNum).padStart(4, '0'));

// 2. Phishing Check
const typeRaw = String(lastRow['Incident Type'] || '').trim();
const is_phishing = typeRaw.toLowerCase().includes('phishing') || typeRaw.toLowerCase().includes('suspicious email');

// 3. Date Parsing Logic (Special Fix for "46124" format)
const parseDate = (rawDate) => {
    if (!rawDate) return '';

    // Agar date number format mein hai (jaise 46124)
    const num = Number(rawDate);
    if (!isNaN(num) && num > 30000 && num < 60000) {
        // Excel Serial Date to Date Object
        const dateObj = new Date((num - 25569) * 86400 * 1000);
        // Format: YYYY-MM-DD ya aap apni pasand ka format rakh sakte hain
        return dateObj.toISOString().split('T')[0]; 
    }

    // Agar date pehle se text hai (jaise "April 10, 2026")
    return String(rawDate).trim();
};

return [{
  json: {
    incident_id:        incidentId,
    reporter_name:      String(lastRow['Reporter Name'] || '').trim(),
    reporter_email:     String(lastRow['Email'] || '').trim(),
    department:         String(lastRow['Department'] || '').trim(),
    incident_type:      typeRaw,

    // Yahan date logic apply ho raha hai
    date_of_incident:   parseDate(lastRow['Date of Incident']), 

    eml_file_drive_url: String(lastRow['EML File (Drive URL)'] || '').trim(),
    description:        String(lastRow['Description'] || '').trim(),
    is_phishing,
    severity:           'Low',
    timestamp_processed: new Date().toISOString()
  }
}];

// 1. Pehle binary data ko direct read karo
const item = $input.first();
let emlContent = '';

try {
  const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
  emlContent = binaryData.toString('latin1');
} catch (e) {
  throw new Error("Binary data 'data' nahi mila. Download node ki output check karein.");
}

// 2. Decode quoted-printable logic
const decodeQP = (str) => str
  .replace(/=\r\n/g, '').replace(/=\n/g, '')
  .replace(/=([0-9A-Fa-f]{2})/g, (_, h) => String.fromCharCode(parseInt(h, 16)));

const emlDecoded = decodeQP(emlContent);

// 3. Header extractor logic
const hdr = (name) => {
  const m = emlContent.match(new RegExp(`^${name}:\\s*(.+)`, 'im'));
  return m ? m[1].trim() : '';
};

// 4. Extract URLs & Filter Whitelist
const rawUrls = emlDecoded.match(/https?:\/\/[^\s"'<>\\)]+/g) || [];
const cleanUrls = [...new Set(
  rawUrls
    .map(u => u.replace(/[)"'<>\\]+$/, '').trim())
    .filter(u => u.length > 10)
    .filter(u => !u.includes('mail.google.com') && !u.includes('schemas.microsoft') && !u.includes('n8n.io') && !u.includes('keenu.pk'))
)].slice(0, 5);

// 5. Auth & Hop Analysis
const fromHeader = hdr('From');
const senderDomain = (fromHeader.match(/@([\w.-]+)/) || [])[1] || '';
const allReceived = [...emlContent.matchAll(/^Received:([\s\S]+?)(?=^\S)/gim)]
  .map(m => m[1].replace(/\s+/g, ' ').trim());

const spfRaw = hdr('Received-SPF');
const spf = /pass/i.test(spfRaw) ? 'PASS' : /fail/i.test(spfRaw) ? 'FAIL' : 'UNKNOWN';
const dkim = /^DKIM-Signature:/im.test(emlContent) ? 'PRESENT' : 'MISSING';
const dmarcRaw = hdr('Authentication-Results');
const dmarc = /dmarc=pass/i.test(dmarcRaw) ? 'PASS' : /dmarc=fail/i.test(dmarcRaw) ? 'FAIL' : 'UNKNOWN';

const authScore = [spf === 'PASS', dkim === 'PRESENT', dmarc === 'PASS'].filter(Boolean).length;
const authVerdict = authScore === 3 ? 'TRUSTED' : authScore >= 2 ? 'SUSPICIOUS' : 'UNTRUSTED';

const fromEmail = (fromHeader.match(/<(.+)>/) || [])[1] || fromHeader;
const returnPath = hdr('Return-Path').replace(/[<>]/g, '').trim();
const pathMismatch = !!(fromEmail && returnPath && fromEmail !== returnPath);

// --- NAYA LOGIC YAHAN HAI ---
// Agar cleanUrls mein kuch nahi bacha, toh senderDomain dekho, 
// lekin agar senderDomain bhi keenu.pk ya n8n.io hai toh usko bhi block kardo.
let finalVtTarget = cleanUrls[0] || '';

if (!finalVtTarget && senderDomain) {
    if (!senderDomain.includes('keenu.pk') && !senderDomain.includes('n8n.io')) {
        finalVtTarget = 'http://' + senderDomain;
    }
}
// -----------------------------

// 6. Return Data
return [{
  json: {
    ...item.json,
    eml_headers: {
      from: fromHeader,
      subject: hdr('Subject'),
      spf, dkim, dmarc,
      auth_score: `${authScore}/3`,
      auth_verdict: authVerdict,
      path_mismatch: pathMismatch,
      urls: cleanUrls
    },
    vt_target: finalVtTarget // Ab ye strictly filtered URL/Domain bhejega
  }
}];

const d = $input.first().json;
const text = `${d.description || ''} ${d.incident_type || ''}`;

// Try to find a full URL first, then a bare domain
const fullUrl = (text.match(/https?:\/\/[\w\-./?=%&#+@!]+/) || [])[0];
const domain  = !fullUrl
  ? (text.match(/\b([\w-]+\.(xyz|com|net|org|io|pk|co|info|biz|online|site|app|dev|link|click)[^\s]*)/) || [])[1]
  : null;

const vt_target = fullUrl || (domain ? 'http://' + domain : '');

return [{ json: { ...d, eml_headers: null, vt_target } }];

const d = $input.first().json;
const target = (d.vt_target || '').trim();

if (!target) {
  return [{ json: { ...d, vt_result: { verdict: 'N/A', malicious: 0, suspicious: 0,
    harmless: 0, undetected: 0, threat_level: 'NONE', scan_url: '', scanned_url: '' } } }];
}

// base64url encode per VT v3 spec
const urlId = Buffer.from(target).toString('base64')
  .replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

let vt = {};
try {
  vt = await this.helpers.httpRequest({
    method:  'GET',
    url:     `https://www.virustotal.com/api/v3/urls/${urlId}`,
    headers: { 'x-apikey': $vars.VIRUSTOTAL_API_KEY || '181ff84dff96e105ed77850ac425bd5ce8809b0f314eb7939c972284f768e7e7' },
    json:    true
  });
} catch (e) {
  vt = { _error: e.message };
}

const stats     = vt?.data?.attributes?.last_analysis_stats || {};
const malicious  = stats.malicious  || 0;
const suspicious = stats.suspicious || 0;
const harmless   = stats.harmless   || 0;
const undetected = stats.undetected || 0;

const verdict     = malicious > 0 ? 'MALICIOUS' : suspicious > 0 ? 'SUSPICIOUS' : (!vt._error ? 'CLEAN' : 'ERROR');
const threat_level = malicious > 0 ? 'CRITICAL' : suspicious > 0 ? 'HIGH' : 'LOW';

return [{
  json: {
    ...d,
    vt_result: {
      verdict, malicious, suspicious, harmless, undetected, threat_level,
      scan_url:    vt?.data?.id ? `https://www.virustotal.com/gui/url/${vt.data.id}` : '',
      scanned_url: target
    }
  }
}];

