return [{
  json: {
    ...d,
    vt_result: {
      verdict, malicious, suspicious, harmless, undetected, threat_level,
      scan_url:    vt?.data?.id ? `https://www.virustotal.com/gui/url/${vt.data.id}` : '',
      scanned_url: target
    }
  }
}];

const d   = $input.first().json;
const vt  = d.vt_result   || {};
const hdr = d.eml_headers || {};

// ── EML Analysis: one concise cell ───────────────────────────
const emlParts = [
  `SPF:${hdr.spf || 'N/A'} DKIM:${hdr.dkim || 'N/A'} DMARC:${hdr.dmarc || 'N/A'}`,
  hdr.path_mismatch   ? 'Return-Path mismatch'      : null,
  hdr.domain_mismatch ? 'Domain mismatch'            : null,
  hdr.suspicious_hop  ? `Suspicious hop (${hdr.hop_count} hops)` : null,
].filter(Boolean).join(' | ');

// ── VT Result: one concise cell ──────────────────────────────
const vtSummary = vt.verdict === 'N/A'
  ? 'No URL found'
  : `${vt.verdict} | ${vt.scanned_url || ''} | ${vt.scan_url ? vt.scan_url : ''}`;

return [{
  json: {
    ...d,
    eml_analysis_summary: emlParts || 'No anomalies',
    vt_summary: vtSummary
  }
}];

const d  = $input.first().json;
const vt = d.vt_result || {};

const vtSummary = vt.verdict === 'N/A'
  ? 'No URL found'
  : `${vt.verdict} | ${vt.scanned_url || ''} | ${vt.scan_url ? vt.scan_url : ''}`;

return [{
  json: {
    ...d,
    eml_analysis_summary: '',
    vt_summary: vtSummary
  }
}];

